    // Since m * n <= 1000, DP complexity O(m*n) is fine.

    // dp[i][j] will store the set of all possible XOR sums to reach cell (i, j).
    // Using mutable.HashSet for efficient set operations.
    val dp: Array[Array[mutable.Set[Int]]] = Array.fill(m)(Array.fill(n)(mutable.HashSet[Int]()))

